// Collect wood logs until the specified target count is reached.
async function collectWoodLogs(bot, params = {}) { 
    const { logType, targetCount } = params;
    bot.chat(`开始任务：收集 ${logType} 原木，目标数量为 ${targetCount} 个`);
    let currentLogs = bot.inventory.items().find(item => item.name === logType);
    let currentCount = currentLogs ? currentLogs.count : 0;
    bot.chat(`当前背包中有 ${currentCount} 个 ${logType}。`);
    if (currentCount >= targetCount) {
        bot.chat(`已有至少 ${targetCount} 个 ${logType}，任务完成！`);
        return;
    }
    bot.chat(`开始收集 ${logType} 原木...`);
    await collectMoreLogs(bot, { logType, targetCount });
    currentLogs = bot.inventory.items().find(item => item.name === logType);
    currentCount = currentLogs ? currentLogs.count : 0;
    bot.chat(`成功收集了 ${currentCount} 个 ${logType}，任务完成！`);
}

